     1→export const DEFAULT_PROFILE_LAYOUT = {
     2→    version: 1,
     3→    preset: "classic",
     4→    spacing: "md",
     5→    radius: "lg",
     6→    sections: [
     7→        { id: "stats", visible: true, size: "md", x: 24, y: 16 },
     8→        { id: "bio", visible: true, size: "md", x: 24, y: 108 },
     9→        { id: "joined_date", visible: true, size: "md", x: 24, y: 196 },
    10→    ],
    11→};
    12→
    13→export const PROFILE_SECTION_LABELS = {
    14→    stats: "Stats",
    15→    bio: "Bio",
    16→    joined_date: "Joined date",
    17→};
    18→
    19→export const PROFILE_SECTION_CODES = {
    20→    stats: "ST",
    21→    bio: "BIO",
    22→    joined_date: "JD",
    23→};
    24→
    25→export const PROFILE_SECTION_IDS = Object.keys(PROFILE_SECTION_LABELS);
    26→export const PROFILE_SECTION_SIZES = ["sm", "md", "lg"];
    27→export const PROFILE_WIDGET_TYPES = ["note", "photo-notes"];
    28→export const PROFILE_WIDGET_BLOCK_TYPES = ["text", "image"];
    29→export const PROFILE_WIDGET_SIZES = ["sm", "md", "lg"];
    30→export const PROFILE_WIDGET_GRID_SIZE = 24;
    31→export const PROFILE_SECTION_GRID_SIZE = 24;
    32→export const PROFILE_HERO_SECTION_IDS = ["stats", "bio", "joined_date"];
    33→
    34→export const normalizeProfileWidgetType = (type) => {
    35→    if (type === "photo_note" || type === "photo_notes" || type === "photo-note") {
    36→        return "photo-notes";
    37→    }
    38→
    39→    return type;
    40→};
    41→
    42→export const isPhotoNoteType = (type) =>
    43→    normalizeProfileWidgetType(type) === "photo-notes";
    44→
    45→export const getDefaultSectionPosition = (sectionId) => {
    46→    if (sectionId === "stats") {
    47→        return { x: 24, y: 16 };
    48→    }
    49→
    50→    if (sectionId === "bio") {
    51→        return { x: 24, y: 108 };
    52→    }
    53→
    54→    return { x: 24, y: 196 };
    55→};
