    60→        handleWidgetFieldChange,
    61→        handleOpenWidgetImagePicker,
    62→        handleWidgetImageUpload,
    63→        handleRemoveBlock,
    64→        handleBlockFieldChange,
    65→        handleOpenBlockColorPicker,
    66→        handleBlockColorChange,
    67→        handleOpenBlockImagePicker,
    68→        handleDeleteBlockImage,
    69→        handleBlockImageUpload,
