    81→
    82→    const renderWidgetImage = (widget) => (
    83→        <div
    84→            className={`profile-widget-image-wrapper${widgetImageResizeState?.widgetId === widget.id ? ' is-resizing' : ''}`}
    85→            style={{width: Number.isFinite(widget.image_width) ? `${widget.image_width}px` : undefined}}
    86→        >
    87→            <img
    88→                className="profile-widget-image"
    89→                src={widget.image_url}
    90→                alt={widget.title || 'widget'}
    91→                draggable="false"
    92→                style={{
    93→                    height: Number.isFinite(widget.image_height) ? `${widget.image_height}px` : undefined,
    94→                    width: Number.isFinite(widget.image_width) ? '100%' : undefined
    95→                }}
    96→            />
    97→            <button
    98→                type="button"
    99→                className="profile-widget-image-delete-btn"
   100→                onClick={() => handleDeleteWidgetImage(widget.id, widget.image_url)}
   101→                aria-label="Remove image"
   102→            >
   103→                <svg xmlns="http://www.w3.org/2000/svg" height="12px" viewBox="0 -960 960 960" width="12px" fill="currentColor"><path d="m256-200-56-56 224-224-224-224 56-56 224 224 224-224 56 56-224 224 224 224-56 56-224-224-224 224Z"/></svg>
   104→            </button>
   105→            {(Number.isFinite(widget.image_width) || Number.isFinite(widget.image_height)) && (
   106→                <div className="profile-widget-image-dimensions">
   107→                    {widget.image_width ?? '—'} &times; {widget.image_height ?? '—'}
   108→                </div>
   109→            )}
   110→            <button type="button" className="profile-widget-image-handle corner-tl" onPointerDown={(e) => handleStartWidgetImageResize(e, widget.id, 'corner-tl')} aria-label="Resize from top-left" />
   111→            <button type="button" className="profile-widget-image-handle corner-tr" onPointerDown={(e) => handleStartWidgetImageResize(e, widget.id, 'corner-tr')} aria-label="Resize from top-right" />
   112→            <button type="button" className="profile-widget-image-handle corner-bl" onPointerDown={(e) => handleStartWidgetImageResize(e, widget.id, 'corner-bl')} aria-label="Resize from bottom-left" />
   113→            <button type="button" className="profile-widget-image-handle corner-br" onPointerDown={(e) => handleStartWidgetImageResize(e, widget.id, 'corner-br')} aria-label="Resize from bottom-right" />
   114→            <button type="button" className="profile-widget-image-handle side-right" onPointerDown={(e) => handleStartWidgetImageResize(e, widget.id, 'right')} aria-label="Resize width" />
   115→            <button type="button" className="profile-widget-image-handle side-bottom" onPointerDown={(e) => handleStartWidgetImageResize(e, widget.id, 'bottom')} aria-label="Resize height" />
   116→        </div>
   117→    );
   118→    const renderBlockImage = (widgetId, block, { onDragStart, elementKey } = {}) => {
   119→        if(!block?.image_url){
   120→            return null;
   121→        }
   122→        const isActive = activeBlockImageState?.widgetId === widgetId && activeBlockImageState?.blockId === block.id;
   123→        const isResizing = blockImageResizeState?.widgetId === widgetId && blockImageResizeState?.blockId === block.id;
   124→        return (
   125→            <div
   126→                key={elementKey}
   127→                className={`profile-widget-block-image-wrapper${isActive ? ' is-active' : ''}${isResizing ? ' is-resizing' : ''}`}
   128→                style={{width: Number.isFinite(block.image_width) ? `${block.image_width}px` : undefined}}
   129→                onPointerDown={(e) => {
   130→                    if(!(e.target instanceof Element)) return;
   131→                    if(e.target.closest('button')){
   132→                        e.stopPropagation();
   133→                        return;
   134→                    }
   135→                    if(onDragStart){
   136→                        onDragStart(e, widgetId, block.id);
