   146→                    className="profile-widget-block-image"
   147→                    src={block.image_url}
   148→                    alt={block.title || 'block'}
   149→                    draggable="false"
   150→                    style={{
   151→                        height: Number.isFinite(block.image_height) ? `${block.image_height}px` : undefined,
   152→                        width: Number.isFinite(block.image_width) ? '100%' : undefined
   153→                    }}
   154→                />
   155→                {(Number.isFinite(block.image_width) || Number.isFinite(block.image_height)) && (
   156→                    <div className="profile-widget-image-dimensions">
   157→                        {block.image_width ?? '—'} &times; {block.image_height ?? '—'}
   158→                    </div>
   159→                )}
   160→                {(Number.isFinite(block.image_width) || Number.isFinite(block.image_height)) && (
   161→                    <button
   162→                        type="button"
   163→                        className="profile-widget-block-image-reset-btn"
   164→                        onPointerDown={(e) => {
   165→                            e.stopPropagation();
   166→                        }}
   167→                        onClick={(e) => {
   168→                            e.stopPropagation();
   169→                            handleResetBlockImageSize(widgetId, block.id);
   170→                        }}
   171→                    >
   172→                        Reset
   173→                    </button>
   174→                )}
   175→                <button type="button" className="profile-widget-image-handle corner-tl" onPointerDown={(e) => handleStartBlockImageResize(e, widgetId, block.id, 'corner-tl')} aria-label="Resize block image from top-left" />
   176→                <button type="button" className="profile-widget-image-handle corner-tr" onPointerDown={(e) => handleStartBlockImageResize(e, widgetId, block.id, 'corner-tr')} aria-label="Resize block image from top-right" />
   177→                <button type="button" className="profile-widget-image-handle corner-bl" onPointerDown={(e) => handleStartBlockImageResize(e, widgetId, block.id, 'corner-bl')} aria-label="Resize block image from bottom-left" />
   178→                <button type="button" className="profile-widget-image-handle corner-br" onPointerDown={(e) => handleStartBlockImageResize(e, widgetId, block.id, 'corner-br')} aria-label="Resize block image from bottom-right" />
   179→                <button type="button" className="profile-widget-image-handle side-right" onPointerDown={(e) => handleStartBlockImageResize(e, widgetId, block.id, 'right')} aria-label="Resize block image width" />
   180→                <button type="button" className="profile-widget-image-handle side-bottom" onPointerDown={(e) => handleStartBlockImageResize(e, widgetId, block.id, 'bottom')} aria-label="Resize block image height" />
   181→            </div>
   182→        );
   183→    };
   184→    const renderReadOnlyBlockContent = (widgetId, block) => {
   185→        if(block.type === 'text'){
   186→            return <p className="profile-widget-block-text">{block.content}</p>;
   187→        }
   188→        if(block.type !== 'image'){
   189→            return null;
   190→        }
   191→
   192→        const imageContent = [];
   193→        if(block.title){
   194→            imageContent.push(
   195→                <p key={`${block.id}-title`} className="profile-widget-block-title">{block.title}</p>
   196→            );
   197→        }
   198→
   199→        const imageNode = renderBlockImage(widgetId, block, {
   200→            onDragStart: handleStartBlockDrag,
   201→            elementKey: `${block.id}-image`
   202→        });
   203→        if(imageNode){
   204→            imageContent.push(imageNode);
   205→        }
   206→
   207→        if(block.note){
   208→            imageContent.push(
   209→                <p key={`${block.id}-note`} className="profile-widget-block-note">{block.note}</p>
   210→            );
   211→        }
   212→
   213→        return imageContent;
   214→    };
   215→    const renderBlockResizeHandles = (widgetId, block) => (
   216→        <>
   217→            <button
   218→                type="button"
   219→                className="profile-widget-block-resize-handle side-right"
   220→                onPointerDown={(e) => handleStartBlockResize(e, widgetId, block.id, 'right')}
   221→                aria-label="Resize block width"
   222→            />
   223→            <button
   224→                type="button"
   225→                className="profile-widget-block-resize-handle side-bottom"
   226→                onPointerDown={(e) => handleStartBlockResize(e, widgetId, block.id, 'bottom')}
   227→                aria-label="Resize block height"
   228→            />
   229→            <button
   230→                type="button"
   231→                className="profile-widget-block-resize-handle corner-br"
   232→                onPointerDown={(e) => handleStartBlockResize(e, widgetId, block.id, 'corner-br')}
   233→                aria-label="Resize block"
   234→            />
   235→        </>
   236→    );
   237→    const renderWidgetCardResizeHandles = (widget, isVisible = false) => {
   238→        if(!isVisible){
   239→            return null;
   240→        }
   241→        return (
   242→            <>
   243→                <button
   244→                    type="button"
   245→                    className="profile-widget-block-resize-handle side-left profile-widget-card-resize-handle"
   246→                    onPointerDown={(e) => handleStartWidgetResize(e, widget.id, 'left')}
   247→                    aria-label="Resize widget width from left"
   248→                />
   249→                <button
   250→                    type="button"
   251→                    className="profile-widget-block-resize-handle side-right profile-widget-card-resize-handle"
   252→                    onPointerDown={(e) => handleStartWidgetResize(e, widget.id, 'right')}
   253→                    aria-label="Resize widget width from right"
   254→                />
   255→                <button
   256→                    type="button"
   257→                    className="profile-widget-block-resize-handle side-top profile-widget-card-resize-handle"
   258→                    onPointerDown={(e) => handleStartWidgetHeightResize(e, widget.id, 'top')}
   259→                    aria-label="Resize widget height from top"
   260→                />
   261→                <button
   262→                    type="button"
   263→                    className="profile-widget-block-resize-handle side-bottom profile-widget-card-resize-handle"
   264→                    onPointerDown={(e) => handleStartWidgetHeightResize(e, widget.id, 'bottom')}
   265→                    aria-label="Resize widget height from bottom"
   266→                />
   267→                <button
   268→                    type="button"
   269→                    className="profile-widget-block-resize-handle side-right-corners profile-widget-card-resize-handle"
   270→                    onPointerDown={(e) => handleStartWidgetCornerResize(e, widget.id, 'side-right-corners')}
   271→                    aria-label="Resize widget from corner"
   272→                />
   273→            </>
   274→        );
   275→    };
   276→    return(
   277→                    <div
   278→                        ref={sectionCanvasRef}
   279→                        className={`profile-layout-sections ${showLayoutBuilder ? 'is-editing' : ''}`}
   280→                            style={{
   281→                                minHeight: `${sectionCanvasHeight}px`,
   282→                                ...(isMobileLayoutViewport
   283→                                    ? {maxWidth: Number.isFinite(mobileCanvasWidth) ? `${mobileCanvasWidth}px` : '100%'}
   284→                                    : null)
   285→                            }}
   286→                        >
   287→                            {visibleProfileSections.map((section) => {
   288→                                if(['stats', 'bio', 'joined_date'].includes(section.id)) return null;
   289→                                const sectionSize = getProfileSectionSize(section.id);
   290→                                let sectionNode = null;
   291→
   292→                                const sectionContentStyle = {
   293→                                    width: Number.isFinite(section.content_width) ? `${section.content_width}px` : undefined,
   294→                                    minHeight: Number.isFinite(section.content_height) ? `${section.content_height}px` : undefined
   295→                                };
   296→
   297→                                if(section.id === 'stats'){
   298→                                    sectionNode = (
   299→                                        <div className="profile-stats-container" style={sectionContentStyle}>
   300→                                            <div className="profile-stat-item">
   301→                                                <span className="stat-number">{formatCounts(user?.followerCount)}</span>
   302→                                                <span className="stat-label">Followers</span>
   303→                                            </div>
   304→                                            <div className="profile-stat-item">
   305→                                                <span className="stat-number">{formatCounts(user?.followingCount)}</span>
   306→                                                <span className="stat-label">Following</span>
   307→                                            </div>
   308→                                        </div>
   309→                                    );
   310→                                }
   311→
   312→                                if(section.id === 'bio'){
   313→                                    sectionNode = (
   314→                                        <div className="profile-bio-container" style={sectionContentStyle}>
   315→                                            <p className="profile-bio">
   316→                                                {userData?.bio}
   317→                                            </p>
   318→                                        </div>
   319→                                    );
   320→                                }
   321→
   322→                                if(section.id === 'joined_date'){
   323→                                    sectionNode = (
   324→                                        <div className="profile-joined-date" style={sectionContentStyle}>
   325→                                            <p className="profile-date-joined">Joined {new Date(userData?.created_at).toLocaleDateString('en-US', {
   326→                                                month: 'long',
   327→                                                day: '2-digit',
   328→                                                year: 'numeric'
   329→                                            })}</p>
   330→                                        </div>
   331→                                    );
   332→                                }
   333→
   334→                                if(!sectionNode){
   335→                                    return null;
   336→                                }
   337→
   338→                                return (
   339→                                    <div
   340→                                        key={section.id}
   341→                                        data-section-id={section.id}
   342→                                        className={`profile-layout-editable-card profile-section-size-${sectionSize} ${showLayoutBuilder ? 'is-editing' : ''} ${draggingSectionId === section.id ? 'is-dragging' : ''} ${!showLayoutBuilder && activeSectionId === section.id ? 'is-section-active' : ''}`}
   343→                                        style={{
   344→                                            left: `${Number.isFinite(section?.x) ? section.x : 0}px`,
   345→                                            top: `${Number.isFinite(section?.y) ? section.y : 0}px`
   346→                                        }}
   347→                                        onClick={(e) => {
   348→                                            if(showLayoutBuilder){
   349→                                                return;
   350→                                            }
   351→                                            e.stopPropagation();
   352→                                            setActiveWidgetId(null);
   353→                                            setActiveSectionId((prev) => prev === section.id ? null : section.id);
   354→                                        }}
   355→                                        onDragOver={(e) => {
   356→                                            if(!showLayoutBuilder){
   357→                                                return;
   358→                                            }
   359→                                            e.preventDefault();
   360→                                            setSectionDropTarget(section.id);
   361→                                        }}
   362→                                        onDragLeave={() => setSectionDropTarget(null)}
   363→                                        onDrop={(e) => handleDropWidgetToSection(e, section.id)}
   364→                                        onPointerDown={(e) => handleStartSectionContainerMove(e, section.id)}
   365→                                    >
   366→                                        {showLayoutBuilder && (
   367→                                            <div className="profile-inline-editor-row">
   368→                                                <span className="profile-layout-item-code">{PROFILE_SECTION_CODES[section.id] || 'N/A'}</span>
   369→                                            </div>
   370→                                        )}
   371→                                        <div className="profile-resize-shell">
   372→                                            {(showLayoutBuilder || activeSectionId === section.id) && (
   373→                                                <button
   374→                                                    type="button"
   375→                                                    className="profile-side-resize-handle left"
   376→                                                    onPointerDown={(e) => handleStartSectionResize(e, section.id, 'left')}
   377→                                                    aria-label="Resize section from left"
   378→                                                />
