   803→                                                            onPointerDown={(e) => handleStartBlockDrag(e, widget.id, block.id)}
   804→                                                        >
   805→                                                            {renderReadOnlyBlockContent(widget.id, block)}
   806→                                                            {renderBlockResizeHandles(widget.id, block)}
   807→                                                        </div>
   808→                                                    ))}
   809→                                                </div>
   810→                                            )}
   811→                                        </>
   812→                                    )}
   813→                                    {renderWidgetCardResizeHandles(widget, activeWidgetId === widget.id)}
   814→                                </div>
